# flags/config.py — environment-scoped flag store configuration
import os
from enum import Enum

class Environment(str, Enum):
    DEV = "dev"
    STAGING = "staging"
    PROD = "prod"

def get_flag_store_url(env: Environment) -> str:
    urls = {
        Environment.DEV:     os.environ.get("DEV_REDIS_URL",     "redis://localhost:6379/0"),
        Environment.STAGING: os.environ.get("STAGING_REDIS_URL", "redis://staging-redis:6379/1"),
        Environment.PROD:    os.environ.get("PROD_REDIS_URL",     "redis://prod-redis:6379/2"),
    }
    return urls[env]

# Flag namespace by environment — keys never collide
FLAG_KEY_PREFIX = {
    Environment.DEV:     "flags:dev:",
    Environment.STAGING: "flags:staging:",
    Environment.PROD:    "flags:prod:",
}

# Retirement checklist script — run before opening the retirement PR
#!/usr/bin/env python3
"""flags/cli/pre_retirement_check.py — verify a flag is safe to retire."""
import subprocess, sys, json
from pathlib import Path

FLAG_NAME = "ai_summariser_v2"
REDIS_URL = "redis://prod-redis:6379/2"

def check_prod_pct() -> float:
    import redis
    r = redis.from_url(REDIS_URL)
    raw = r.get(f"flags:prod:{FLAG_NAME}")
    if not raw:
        return -1.0
    return json.loads(raw).get("rollout_pct", 0.0)

def check_no_code_references() -> list[str]:
    result = subprocess.run(
        ["git", "grep", "-rn", FLAG_NAME, "--", "*.py", "*.ts", "*.go"],
        capture_output=True, text=True
    )
    return [l for l in result.stdout.splitlines() if "pre_retirement_check" not in l]

def check_hours_at_100() -> float:
    import redis, time
    r = redis.from_url(REDIS_URL)
    raw = r.get(f"flags:prod:{FLAG_NAME}")
    if not raw:
        return 0.0
    data = json.loads(raw)
    history = data.get("rollout_history", [])
    for entry in reversed(history):
        if entry["to_pct"] == 100.0:
            promoted_at = entry["at"]
            import datetime
            promoted_dt = datetime.datetime.fromisoformat(promoted_at.replace("Z", "+00:00"))
            hours = (datetime.datetime.now(datetime.timezone.utc) - promoted_dt).total_seconds() / 3600
            return round(hours, 1)
    return 0.0

if __name__ == "__main__":
    errors = []
    pct = check_prod_pct()
    if pct < 100.0:
        errors.append(f"Flag rollout_pct is {pct}%, must be 100% before retirement")

    hours = check_hours_at_100()
    if hours < 72.0:
        errors.append(f"Flag has been at 100% for only {hours}h (need ≥ 72h)")

    refs = check_no_code_references()
    if refs:
        errors.append(f"Flag still referenced in code ({len(refs)} locations — remove before retiring):")
        for r in refs[:5]:
            errors.append(f"  {r}")

    if errors:
        print("PRE-RETIREMENT CHECK FAILED:")
        for e in errors:
            print(f"  ✗ {e}")
        sys.exit(1)
    else:
        print(f"✓ Flag {FLAG_NAME} is safe to retire")
        print(f"  Rollout: 100% | Hours at 100%: {hours}h | No code references")
